headStyles:
/* === About Page Specific Styles === */

body { background: var(--dark-bg); }

/* Animated hero tagline */
.about-tagline {
  font-family: 'Montserrat', sans-serif;
  font-size: clamp(12px, 1.8vw, 15px);
  font-weight: 700;
  letter-spacing: 6px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.55);
  margin-top: 20px;
  overflow: hidden;
}
.about-tagline span {
  display: inline-block;
  opacity: 0;
  transform: translateY(12px);
  animation: taglineIn 0.5s ease forwards;
}
@keyframes taglineIn {
  to { opacity: 1; transform: translateY(0); }
}

/* Numbered sections */
.about-section {
  position: relative;
  padding: var(--section-pad) 0;
}
.about-section:nth-child(even) {
  background: var(--bg-light);
}
.section-number {
  font-family: 'Montserrat', sans-serif;
  font-size: clamp(80px, 10vw, 140px);
  font-weight: 900;
  color: rgba(255, 255, 255, 0.03);
  position: absolute;
  top: 20px;
  left: 24px;
  line-height: 1;
  user-select: none;
  pointer-events: none;
  z-index: 0;
}
.about-section .container {
  position: relative;
  z-index: 1;
}

/* Difference list items */
.diff-list {
  list-style: none;
  padding: 0;
  margin: 28px 0 0;
  display: flex;
  flex-direction: column;
  gap: 0;
}
.diff-item {
  display: flex;
  align-items: flex-start;
  gap: 16px;
  padding: 20px 0;
  border-bottom: 1px solid var(--border-light);
  transition: padding 0.3s ease, background 0.3s ease;
}
.diff-item:last-child { border-bottom: none; }
.diff-item:hover {
  padding-left: 12px;
  background: rgba(115, 215, 238, 0.03);
  border-radius: 8px;
}
.diff-icon {
  flex-shrink: 0;
  width: 36px;
  height: 36px;
  border-radius: 8px;
  background: rgba(0, 77, 255, 0.12);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-accent);
  transition: all 0.3s ease;
}
.diff-item:hover .diff-icon {
  background: var(--color-blue);
  color: var(--text-white);
  transform: scale(1.1);
}
.diff-text {
  font-size: 15px;
  color: var(--text-secondary);
  line-height: 1.65;
  flex: 1;
}

.closing-statement {
  font-family: 'Montserrat', sans-serif;
  font-size: 18px;
  font-weight: 600;
  color: var(--text-white);
  margin-top: 32px;
  padding: 24px;
  background: rgba(0, 77, 255, 0.08);
  border-left: 4px solid var(--color-light-blue);
  border-radius: 0 8px 8px 0;
}

/* What We Do cards */
.wwd-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 24px;
  margin-top: 40px;
}
.wwd-card {
  background: var(--bg-white);
  border: 1px solid var(--border-light);
  border-radius: 12px;
  padding: 32px 28px;
  position: relative;
  overflow: hidden;
  transition: transform 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94), box-shadow 0.4s ease, border-color 0.4s ease;
}
.wwd-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 3px;
  background: var(--pride-gradient);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.4s ease;
}
.wwd-card:hover::before { transform: scaleX(1); }
.wwd-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.25);
  border-color: rgba(115, 215, 238, 0.25);
}
.wwd-card-icon {
  width: 48px;
  height: 48px;
  border-radius: 10px;
  background: linear-gradient(135deg, rgba(0, 77, 255, 0.15), rgba(115, 215, 238, 0.18));
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-accent);
  margin-bottom: 18px;
  transition: all 0.3s ease;
}
.wwd-card:hover .wwd-card-icon {
  transform: rotate(-5deg) scale(1.1);
  background: linear-gradient(135deg, rgba(0, 77, 255, 0.28), rgba(115, 215, 238, 0.3));
}
.wwd-card h3 {
  font-size: 17px;
  margin-bottom: 10px;
  color: var(--text-white);
}
.wwd-card p {
  font-size: 14px;
  color: var(--text-secondary);
  line-height: 1.65;
}

/* Meet the Board CTA */
.board-cta {
  text-align: center;
  padding: 40px 0 20px;
  position: relative;
}
.board-cta::before {
  content: '';
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 120px;
  height: 3px;
  background: var(--pride-gradient);
  border-radius: 2px;
}
.board-cta h2 {
  font-size: 28px;
  margin-top: 28px;
  margin-bottom: 12px;
}
.board-cta p {
  font-size: 16px;
  color: var(--text-secondary);
  max-width: 520px;
  margin: 0 auto 28px;
  line-height: 1.65;
}
.btn-board-cta {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 16px 36px;
  font-size: 16px;
  font-weight: 700;
  background: transparent;
  border: 2px solid var(--color-light-blue);
  color: var(--color-light-blue);
  border-radius: 8px;
  transition: all 0.3s ease;
  text-decoration: none;
  font-family: 'Montserrat', sans-serif;
  letter-spacing: 0.5px;
}
.btn-board-cta:hover {
  background: var(--color-light-blue);
  color: var(--dark-bg);
  transform: translateY(-2px);
  box-shadow: 0 8px 28px rgba(115, 215, 238, 0.3);
}
.btn-board-cta svg { transition: transform 0.3s ease; }
.btn-board-cta:hover svg { transform: translateX(4px); }

@media (max-width: 768px) {
  .wwd-grid { grid-template-columns: 1fr; }
  .section-number { font-size: 60px; }
  .about-tagline { letter-spacing: 3px; }
}

inlineScripts:
/* About Page: Animated Tagline */
(function () {
  var tagline = 'ENDORSE . MOBILIZE . FIGHT FOR OHIO .';
  var container = document.getElementById('aboutTagline');
  if (!container) return;
  tagline.split('').forEach(function (char, i) {
    var span = document.createElement('span');
    span.textContent = char === ' ' ? '\u00A0' : char;
    span.style.animationDelay = (0.6 + i * 0.03) + 's';
    container.appendChild(span);
  });
})();

/* Parallax on section numbers */
(function () {
  var nums = document.querySelectorAll('.section-number');
  if (!nums.length) return;
  window.addEventListener('scroll', function () {
    nums.forEach(function (num) {
      var rect = num.parentElement.getBoundingClientRect();
      var offset = (rect.top + rect.height / 2) / window.innerHeight;
      num.style.transform = 'translateY(' + (offset * 40 - 20) + 'px)';
    });
  }, { passive: true });
})();

/* Tilt effect on What We Do cards */
(function () {
  var cards = document.querySelectorAll('.wwd-card');
  cards.forEach(function (card) {
    card.addEventListener('mousemove', function (e) {
      var rect = card.getBoundingClientRect();
      var x = (e.clientX - rect.left) / rect.width - 0.5;
      var y = (e.clientY - rect.top) / rect.height - 0.5;
      card.style.transform = 'translateY(-4px) perspective(600px) rotateX(' + (y * -4) + 'deg) rotateY(' + (x * 4) + 'deg)';
    });
    card.addEventListener('mouseleave', function () {
      card.style.transform = '';
    });
  });
})();
